function localeIdsFromCountries(countryCsv) {
  const codes = String(countryCsv || "")
    .split(/[\s,]+/)
    .map((s) => s.trim().toUpperCase())
    .filter((c) => /^[A-Z]{2}$/.test(c));
  const effective = codes.length ? codes : ["LK"];
  const ids = new Set();
  for (const code of effective) {
