      const message = document.querySelector("#previewMessage")?.value || "";
      const headline = document.querySelector("#previewHeadline")?.value || "";
      const description = document.querySelector("#previewDescription")?.value || "";
      const link = document.querySelector("#previewLink")?.value || "";
      const cta = document.querySelector("#previewCta")?.value || "";
      const mediaUrl = document.querySelector("#previewMediaUrl")?.value || "";
      const mediaType = document.querySelector("#previewMediaType")?.value || "image";
      const cardsRaw = document.querySelector("#previewCarouselCards")?.value || "[]";
      let carouselCards = [];
      try {
        const parsed = JSON.parse(cardsRaw);
        carouselCards = Array.isArray(parsed) ? parsed : [];
      } catch {
        appState.error = "Carousel cards must be valid JSON array.";
        render();
        return;
      }
      try {
        /** Server + UI need 2+ cards for carousel preview; always send parsed JSON (not only when Media type = Carousel). */
        const hasMultiCarousel = carouselCards.length >= 2;
        const data = await apiFetch("/api/preview/render", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            pageName,
            message,
            headline,
            description,
            link,
            cta,
            imageUrl: mediaType === "video" && !hasMultiCarousel ? undefined : mediaUrl || undefined,
            file_url: mediaType === "video" && !hasMultiCarousel ? mediaUrl : undefined,
            mode: hasMultiCarousel
              ? "carousel"
              : mediaType === "carousel"
                ? "carousel"
                : mediaType === "video"
                  ? "video"
                  : undefined,
            carouselCards: carouselCards.length ? carouselCards : undefined,
          }),
        });
        const fromApi = data.adPreview || dashboard.adPreview;
        /** Keep textarea JSON identical to what the user submitted (server used to return a narrowed object). */
        dashboard.adPreview = {
          ...fromApi,
          carouselCards:
            carouselCards.length > 0 ? JSON.parse(JSON.stringify(carouselCards)) : (fromApi?.carouselCards ?? []),
        };
        persistCarouselCardsEditor(dashboard.adPreview.carouselCards || []);
        render();
      } catch (error) {
        appState.error = error.message;
        render();
      }
    });
