.loading {
  min-height: 100vh;
  display: grid;
  place-content: center;
  color: var(--text);
  font-size: 18px;
  text-align: center;
  padding: 20px;
}

.loading.error {
  color: var(--warn);
}

.json-box {
  margin-top: 12px;
  padding: 10px;
  border: 1px solid var(--line);
  border-radius: 10px;
  background: rgba(9, 18, 33, 0.65);
  color: #d1e3ff;
  font-size: 12px;
  line-height: 1.45;
  overflow: auto;
  max-height: 240px;
}

/* Meta recommended sizes — Creatives / ad preview */
.creative-specs-panel {
  margin: 0 0 16px;
  padding: 12px 14px;
  border-radius: 10px;
  border: 1px solid var(--line);
  background: rgba(9, 18, 33, 0.35);
}

.creative-specs-title {
  margin: 0 0 8px;
  font-size: 13px;
  font-weight: 600;
  color: var(--text);
}

.creative-specs-note {
  margin: 0 0 10px;
  font-size: 12px;
  line-height: 1.4;
  color: var(--muted);
}

.creative-specs-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 12px;
}

.creative-specs-table th,
.creative-specs-table td {
  text-align: left;
  padding: 6px 8px;
  border-bottom: 1px solid var(--line);
  vertical-align: top;
}

.creative-specs-table th {
  color: var(--muted);
  font-weight: 600;
}

.creative-specs-table code {
  font-size: 11px;
  white-space: nowrap;
}

.ad-preview-form .field-hint {
  display: block;
  margin-top: 4px;
  font-size: 11px;
  font-weight: 400;
  color: var(--muted);
  line-height: 1.35;
}

.ad-preview-form .field-hint code {
  font-size: 10px;
}

/* Meta-style ad preview */
.ad-preview-hero .ad-preview-layout,
.ad-preview-card-wrap .ad-preview-device {
  margin-top: 12px;
}

.ad-preview-layout {
  display: grid;
  grid-template-columns: minmax(0, 400px) minmax(260px, 1fr);
  gap: 24px;
  align-items: start;
}

.ad-preview-form {
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.ad-preview-form label {
  display: flex;
  flex-direction: column;
  gap: 4px;
  font-size: 12px;
  color: var(--muted);
}

.ad-preview-form input,
.ad-preview-form textarea,
.ad-preview-form select {
  font: inherit;
  font-size: 13px;
  color: var(--text);
  background: rgba(9, 18, 33, 0.55);
  border: 1px solid var(--line);
  border-radius: 8px;
  padding: 8px 10px;
}

.ad-preview-row {
  flex-direction: row !important;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
}

.ad-preview-row select {
  max-width: 160px;
}

.ad-preview-btn {
  margin-top: 4px;
  align-self: flex-start;
  padding: 10px 18px;
  border-radius: 10px;
  border: 1px solid var(--brand-soft);
  background: rgba(37, 99, 235, 0.22);
  color: var(--text);
  cursor: pointer;
  font-weight: 600;
}

.ad-preview-btn:hover {
  background: rgba(37, 99, 235, 0.35);
}

/* Default frame; premium carousel uses 390px (Meta-style travel ad card) */
.ad-preview-device {
  max-width: 360px;
  width: 100%;
}

.ad-preview-device--premium {
  max-width: 390px;
}

.ad-preview-chrome {
  display: flex;
  gap: 5px;
  justify-content: center;
  padding: 8px 0 10px;
}

.ad-preview-dot {
  width: 7px;
  height: 7px;
  border-radius: 50%;
  background: #3e4c63;
}

.ad-preview-surface {
  background: linear-gradient(180deg, #1c1e21 0%, #18191a 100%);
  border-radius: 14px;
  border: 1px solid #3a3b3c;
  box-shadow: var(--shadow);
  overflow: hidden;
}

.ad-preview-surface--premium {
  border-radius: 28px;
  border: 1px solid rgba(255, 255, 255, 0.08);
  background: linear-gradient(165deg, #1e2128 0%, #121316 48%, #0d0e10 100%);
  box-shadow:
    0 24px 48px rgba(0, 0, 0, 0.45),
    inset 0 1px 0 rgba(255, 255, 255, 0.06);
}

.ad-preview-card {
  background: #242526;
  color: #e4e6eb;
}

.ad-preview-card--carousel-mode .ad-preview-header {
  padding: 10px 16px 0;
}

.ad-preview-card--carousel-mode .ad-preview-primary {
  margin: 8px 16px 10px;
}

.ad-preview-card--carousel-mode .ad-preview-linkbox--carousel {
  padding: 10px 16px 12px;
}

/* Premium travel ad: 390px shell, 18px inset — inner column ≈ 354px (hero ~354×185 @ 1200×628) */
.ad-preview-card--premium.ad-preview-card--carousel-mode {
  padding: 18px 18px 0;
  background: transparent;
}

.ad-preview-card--premium.ad-preview-card--carousel-mode .ad-preview-header {
  padding: 0;
}

.ad-preview-card--premium.ad-preview-card--carousel-mode .ad-preview-primary {
  margin: 8px 0 14px;
  font-size: 14px;
  line-height: 1.45;
  color: #e8eaed;
}

.ad-preview-card--premium.ad-preview-card--carousel-mode .ad-preview-linkbox--carousel.ad-preview-linkbox--premium {
  margin: 0 -18px;
  padding: 18px 18px 20px;
  min-height: 74px;
  box-sizing: border-box;
  align-items: center;
  background: linear-gradient(180deg, rgba(30, 32, 38, 0.98) 0%, #0f1013 100%);
  border-top: 1px solid rgba(255, 255, 255, 0.06);
}

.ad-preview-linkbox--premium .ad-preview-cta {
  padding: 10px 18px;
  border-radius: 10px;
  background: linear-gradient(180deg, #3b82f6 0%, #2563eb 100%);
  color: #fff;
  box-shadow: 0 4px 14px rgba(37, 99, 235, 0.35);
  font-weight: 700;
}

.ad-preview-linkbox--premium .ad-preview-domain {
  font-size: 12px;
  color: #9ca3af;
  text-transform: none;
  letter-spacing: 0.01em;
}

.ad-preview-header {
  display: flex;
  gap: 10px;
  align-items: flex-start;
  padding: 10px 12px 0;
}

.ad-preview-avatar {
  width: 40px;
  height: 40px;
  border-radius: 50%;
  background: linear-gradient(135deg, #1877f2, #42b72a);
  display: grid;
  place-items: center;
  font-weight: 700;
  font-size: 18px;
  color: #fff;
  flex-shrink: 0;
}

.ad-preview-headmeta {
  min-width: 0;
}

.ad-preview-pagename {
  font-weight: 600;
  font-size: 15px;
  line-height: 1.25;
}

.ad-preview-sponsored {
  font-size: 12px;
  color: #b0b3b8;
  margin-top: 2px;
}

.ad-preview-status {
  font-weight: 600;
}

.ad-preview-status--on {
  color: #42b72a;
}

.ad-preview-status--off {
  color: #f59e0b;
}

.ad-preview-primary {
  margin: 8px 12px 10px;
  font-size: 15px;
  line-height: 1.35;
  white-space: pre-wrap;
}

.ad-preview-media {
  display: block;
  width: 100%;
  aspect-ratio: 1.91 / 1;
  object-fit: cover;
  background: #111;
}

.ad-preview-carousel-stack {
  display: flex;
  flex-direction: column;
  gap: 0;
  min-height: 0;
}

.ad-preview-carousel-hero {
  padding: 0 16px 8px;
  flex-shrink: 0;
  overflow: visible;
}

.ad-preview-card--premium .ad-preview-carousel-hero {
  padding: 0 0 4px;
}

/* Premium hero frame + caption bar (syncs with selected strip card) */
.ad-preview-carousel-hero-shell {
  border-radius: 14px;
  overflow: hidden;
  box-shadow:
    0 16px 48px rgba(0, 0, 0, 0.55),
    0 0 0 1px rgba(255, 255, 255, 0.07),
    inset 0 1px 0 rgba(255, 255, 255, 0.06);
  animation: adPreviewHeroReveal 0.38s ease;
}

.ad-preview-carousel-hero-shell--premium {
  display: flex;
  flex-direction: column;
  border-radius: 18px;
  box-shadow:
    0 20px 50px rgba(0, 0, 0, 0.5),
    0 0 0 1px rgba(255, 255, 255, 0.08),
    inset 0 1px 0 rgba(255, 255, 255, 0.05);
}

.ad-preview-carousel-hero-shell--premium .ad-preview-carousel-hero-media-wrap {
  border-radius: 18px 18px 0 0;
}

@keyframes adPreviewHeroReveal {
  from {
    opacity: 0.88;
    transform: scale(0.985);
  }
  to {
    opacity: 1;
    transform: scale(1);
  }
}

/* Hero matches 1200×628 (1.91:1); scales with 360px frame */
.ad-preview-carousel-hero-media-wrap {
  position: relative;
  width: 100%;
  aspect-ratio: 1200 / 628;
  overflow: hidden;
  background: #08090a;
}

.ad-preview-carousel-hero-media {
  position: absolute;
  inset: 0;
  z-index: 1;
  display: block;
  width: 100%;
  height: 100%;
  object-fit: cover;
  object-position: center;
  border-radius: 0;
  background: #111;
}

.ad-preview-carousel-hero-caption {
  display: flex;
  flex-wrap: wrap;
  align-items: baseline;
  gap: 6px 12px;
  padding: 9px 12px 11px;
  background: linear-gradient(145deg, #0c2320 0%, #143d36 42%, #0f2e2a 100%);
  border-top: 1px solid rgba(255, 255, 255, 0.09);
}

/* Title bar below media (not on top of video) — full 1.91:1 frame stays image/video only */
.ad-preview-carousel-hero-caption--below {
  display: flex;
  flex-wrap: nowrap;
  align-items: flex-start;
  flex-shrink: 0;
  gap: 6px 10px;
  padding: 8px 12px 9px;
  border-top: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 0 0 16px 16px;
  background: linear-gradient(145deg, #0f2e28 0%, #143d36 48%, #0c2320 100%);
}

.ad-preview-hero-caption-stack {
  display: flex;
  flex-direction: column;
  align-items: flex-start;
  gap: 2px;
  width: 100%;
  min-width: 0;
}

.ad-preview-hero-badge {
  position: absolute;
  top: 10px;
  left: 10px;
  z-index: 4;
  max-width: min(88%, 240px);
  padding: 5px 10px;
  border-radius: 999px;
  font-size: 10px;
  font-weight: 700;
  line-height: 1.2;
  color: #fff;
  background: rgba(22, 58, 48, 0.92);
  box-shadow: 0 2px 12px rgba(0, 0, 0, 0.42);
  pointer-events: none;
}

/* Badge top-left; keep ★ rating pill on the right */
.ad-preview-carousel-hero-shell--premium .ad-preview-hero-rating-row {
  left: auto;
  right: 10px;
}

.ad-preview-carousel-hero-caption-tour,
.ad-preview-carousel-hero-caption-travelers {
  font-size: 10px;
  font-weight: 500;
  line-height: 1.25;
  color: #9ca3af;
}

.ad-preview-carousel-hero-caption-footer {
  font-size: 9px;
  line-height: 1.25;
  color: #6b7280;
  margin-top: 2px;
}

.ad-preview-carousel-hero-caption-desc {
  font-size: 10px;
  font-weight: 500;
  line-height: 1.3;
  color: #9ca3af;
}

.ad-preview-hero-caption-stack .ad-preview-carousel-hero-caption-title {
  flex: none;
  width: 100%;
}

.ad-preview-carousel-hero-caption--below .ad-preview-carousel-hero-caption-title {
  color: #f4fbf8;
  font-size: 11px;
  line-height: 1.25;
}

.ad-preview-carousel-hero-caption--below .ad-preview-carousel-hero-caption-price {
  color: #a7e8d9;
  font-size: 10px;
}

/* Top-left premium pill: ★ 4.9 ★ Rated (glass bar, gold stars, white type) */
.ad-preview-hero-rating-row {
  position: absolute;
  z-index: 3;
  top: 10px;
  left: 10px;
  bottom: auto;
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 6px 12px 6px 10px;
  border-radius: 12px;
  font-size: 11px;
  font-weight: 700;
  background: rgba(6, 8, 12, 0.52);
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
  box-shadow: 0 4px 16px rgba(0, 0, 0, 0.38);
  border: 1px solid rgba(255, 255, 255, 0.1);
}

.ad-preview-hero-rating-star {
  flex-shrink: 0;
  color: #e8b923;
  font-size: 12px;
  line-height: 1;
  text-shadow:
    0 1px 2px rgba(0, 0, 0, 0.45),
    0 0 8px rgba(232, 185, 35, 0.35);
}

.ad-preview-hero-rating-num {
  color: #ffffff;
  font-size: 11px;
  font-weight: 800;
  letter-spacing: 0.02em;
}

.ad-preview-hero-rating-label {
  font-size: 10px;
  font-weight: 600;
  color: #ffffff;
  letter-spacing: 0.04em;
  text-transform: capitalize;
}

.ad-preview-hero-play {
  position: absolute;
  inset: 0;
  z-index: 2;
  display: flex;
  align-items: center;
  justify-content: center;
  pointer-events: none;
}

.ad-preview-hero-play-icon {
  width: 52px;
  height: 52px;
  border-radius: 50%;
  background: rgba(255, 255, 255, 0.22);
  backdrop-filter: blur(4px);
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.35);
  position: relative;
}

.ad-preview-hero-play-icon::after {
  content: "";
  position: absolute;
  left: 54%;
  top: 50%;
  transform: translate(-50%, -50%);
  border-style: solid;
  border-width: 9px 0 9px 14px;
  border-color: transparent transparent transparent #fff;
}

.ad-preview-carousel-hero-caption-title {
  font-size: 12px;
  font-weight: 700;
  letter-spacing: 0.01em;
  color: #e8f4f1;
  line-height: 1.3;
  flex: 1 1 120px;
  min-width: 0;
}

.ad-preview-carousel-hero-caption-price {
  font-size: 11px;
  font-weight: 700;
  color: #7dd3c0;
  white-space: nowrap;
  letter-spacing: 0.02em;
}

.ad-preview-carousel-strip-title {
  margin: 10px 16px 6px;
  font-size: 11px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.04em;
  color: var(--muted);
  flex-shrink: 0;
}

.ad-preview-carousel-strip-title--premium {
  margin: 0 0 6px;
  display: flex;
  align-items: center;
  gap: 6px;
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 0.12em;
  color: #8b92a4;
}

.ad-preview-strip-sep {
  opacity: 0.7;
  font-weight: 400;
}

.ad-preview-strip-chev {
  font-size: 12px;
  opacity: 0.55;
  letter-spacing: -2px;
}

/* Portrait strip: default ~140px; premium tighter gap so more of 3rd card shows */
.ad-preview-carousel {
  display: grid;
  grid-auto-flow: column;
  grid-auto-columns: 140px;
  gap: 10px;
  overflow-x: auto;
  padding: 6px 16px 14px;
  scroll-snap-type: x proximity;
  scroll-padding-inline: 16px;
  flex: 1 1 auto;
  min-height: 0;
  -webkit-overflow-scrolling: touch;
}

.ad-preview-carousel--premium {
  grid-auto-columns: 116px;
  gap: 8px;
  padding: 0 0 12px;
  scroll-padding-inline: 0;
  align-items: start;
}

.ad-preview-carousel .ad-preview-card-item {
  width: 140px;
  min-width: 140px;
  max-width: 140px;
}

.ad-preview-carousel--premium .ad-preview-card-item {
  width: 116px;
  min-width: 116px;
  max-width: 116px;
  min-height: 0;
  border-radius: 14px;
}

.ad-preview-card-item {
  background: #18191a;
  border: 1px solid rgba(255, 255, 255, 0.12);
  border-radius: 12px;
  overflow: hidden;
  scroll-snap-align: start;
  display: flex;
  flex-direction: column;
  cursor: pointer;
  opacity: 0.78;
  transition:
    opacity 0.22s ease,
    transform 0.22s ease,
    box-shadow 0.22s ease,
    border-color 0.22s ease;
}

.ad-preview-card-item--active {
  opacity: 1;
  border: 2px solid rgba(255, 255, 255, 0.92);
  box-shadow: 0 10px 28px rgba(0, 0, 0, 0.5);
  transform: translateY(-2px);
}

.ad-preview-card-item:focus-visible {
  outline: 2px solid rgba(96, 165, 250, 0.95);
  outline-offset: 2px;
}

.ad-preview-card-item:active {
  transform: translateY(-1px);
}

.ad-preview-card-item--active:active {
  transform: translateY(-1px);
}

.ad-preview-card-media-wrap {
  flex-shrink: 0;
  overflow: hidden;
  background: #0e0f10;
}

/* Default (non-carousel strip): keep feed link ratio */
.ad-preview-card-media {
  width: 100%;
  aspect-ratio: 1.91 / 1;
  object-fit: cover;
  display: block;
}

/* Carousel strip: 4:5 portrait thumbnails */
.ad-preview-carousel .ad-preview-card-media-wrap {
  width: 100%;
  aspect-ratio: 4 / 5;
  position: relative;
}

.ad-preview-carousel .ad-preview-card-media {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  object-fit: cover;
  object-position: center;
  background: #0e0f10;
}

.ad-preview-card-body {
  flex: 0 0 auto;
  min-height: 72px;
  max-height: 88px;
  padding: 8px 10px 9px;
  display: flex;
  flex-direction: column;
  justify-content: flex-start;
  overflow: hidden;
  box-sizing: border-box;
}

.ad-preview-carousel--premium .ad-preview-card-body {
  flex: 1 1 auto;
  min-height: 0;
  max-height: none;
  padding: 8px 9px 10px;
  background: linear-gradient(180deg, #1a1c20 0%, #141518 100%);
}

.ad-preview-carousel--premium .ad-preview-card-title {
  font-size: 11px;
  font-weight: 700;
  color: #f3f4f6;
}

.ad-preview-carousel--premium .ad-preview-card-price {
  color: #9ca3af;
  font-size: 10px;
}

.ad-preview-card-badge {
  position: absolute;
  top: 5px;
  left: 5px;
  z-index: 2;
  max-width: calc(100% - 10px);
  padding: 3px 6px;
  border-radius: 999px;
  font-size: 7px;
  font-weight: 700;
  line-height: 1.15;
  letter-spacing: 0.02em;
  color: #fff;
  background: rgba(22, 58, 48, 0.92);
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.38);
  pointer-events: none;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.ad-preview-carousel--premium .ad-preview-card-tour-type {
  margin: 3px 0 0;
  padding: 0;
  font-size: 9px;
  font-weight: 500;
  line-height: 1.2;
  color: #9ca3af;
}

.ad-preview-carousel--premium .ad-preview-card-travelers {
  margin: 2px 0 0;
  padding: 0;
  font-size: 8px;
  line-height: 1.2;
  color: #8b9099;
}

.ad-preview-carousel--premium .ad-preview-card-footer {
  margin: 4px 0 0;
  padding: 0;
  font-size: 7px;
  line-height: 1.2;
  color: #6b7280;
}

.ad-preview-card-title {
  margin: 0;
  font-size: 12px;
  font-weight: 600;
  line-height: 1.3;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
}

.ad-preview-card-price {
  margin: 4px 0 0;
  font-size: 11px;
  font-weight: 600;
  line-height: 1.25;
  color: #8f9297;
  letter-spacing: 0.01em;
}

.ad-preview-card-text {
  margin: 0;
  color: #b0b3b8;
  font-size: 12px;
  line-height: 1.25;
}

/* Carousel mode: no duplicate headline/description in link row */
.ad-preview-linkbox--carousel {
  align-items: center;
  padding: 8px 12px;
}

.ad-preview-linkcol--compact {
  min-width: 0;
  flex: 1;
}

.ad-preview-linkcol--compact .ad-preview-domain {
  font-size: 12px;
  word-break: break-all;
}

.ad-preview-placeholder {
  display: grid;
  place-items: center;
  color: #8a8d91;
  font-size: 13px;
  padding: 24px;
  aspect-ratio: 1.91 / 1;
}

.ad-preview-linkbox {
  display: flex;
  align-items: stretch;
  gap: 0;
  margin: 0;
  padding: 10px 12px 12px;
  background: #3a3b3c;
  text-decoration: none;
  color: inherit;
  border-top: 1px solid #4e4f50;
}

.ad-preview-linkcol {
  flex: 1;
  min-width: 0;
  padding-right: 10px;
}

.ad-preview-linkheadline {
  font-size: 16px;
  font-weight: 600;
  line-height: 1.25;
  margin-bottom: 4px;
  color: #e4e6eb;
}

.ad-preview-linkdesc {
  font-size: 13px;
  color: #b0b3b8;
  line-height: 1.3;
  margin-bottom: 4px;
}

.ad-preview-domain {
  font-size: 11px;
  color: #8a8d91;
  text-transform: uppercase;
  letter-spacing: 0.02em;
}

.ad-preview-cta {
  align-self: center;
  flex-shrink: 0;
  padding: 8px 12px;
  background: #4b4c4f;
  border-radius: 6px;
  font-size: 14px;
  font-weight: 600;
  color: #e4e6eb;
}

.ad-preview-metaids {
  margin: 8px 12px 12px;
  font-size: 11px;
  color: #8a8d91;
  word-break: break-all;
}

@media (max-width: 1100px) {
  .shell {
    grid-template-columns: 1fr;
  }

  .sidebar {
    position: static;
    height: auto;
    border-right: none;
    border-bottom: 1px solid var(--line);
  }

  .nav {
    flex-direction: row;
    flex-wrap: wrap;
  }

